import { NextResponse } from "next/server";
import { GoogleGenAI } from "@google/genai";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth-config";

/**
 * POST /api/veo-long-ad/chunk-script
 *
 * Beat Planner: analyzes the property script and outputs a typed beat plan
 * for the hybrid pipeline. All beats are generated by Veo; presenter beats
 * use the avatar image as a SUBJECT reference.
 *
 * Beat types:
 *   HOOK           — presenter arrives/steps out of car, 4-5s, cinematic
 *   AVATAR_SEGMENT — presenter explains at property, 5-7s, Veo + Sarvam TTS
 *   PROPERTY_VISUAL— room/area showcase, 4-5s, Veo + Sarvam voiceover
 *   FEATURE_BURST  — price/spec visual, 2-3s, Veo + Sarvam voiceover
 *   CTA            — presenter CTA, 4-6s, Veo + Sarvam TTS
 *
 * Input (FormData):
 *   script: string
 *   language: string
 *   locationImages[]: File[] (1–5)
 *   avatarImages[]:   File[] (1–3)
 *
 * Output (JSON):
 *   {
 *     beats: Beat[],
 *     voiceProfile: string,
 *     fullNarration: string,      — complete spoken text for master TTS track
 *     totalDuration: number,
 *     // legacy compat
 *     chunks: Chunk[],
 *     masterVoicePrompt: string,
 *     totalChunks: number,
 *     totalEstimatedDuration: number,
 *   }
 */

const MAX_BEATS = 10;
const MAX_AVATAR_BEATS = 4;

export async function POST(request) {
  const apiKey = process.env.GEMINI_API_KEY;
  if (!apiKey) {
    return NextResponse.json({ error: "GEMINI_API_KEY is not configured" }, { status: 500 });
  }

  try {
    const session = await getServerSession(authOptions);
    if (!session) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const formData = await request.formData();
    const script = (formData.get("script") || "").toString().trim();
    const language = (formData.get("language") || "english").toString();

    if (!script || script.length < 20) {
      return NextResponse.json({ error: "script is required (min 20 chars)" }, { status: 400 });
    }

    const locationImages = [];
    for (let i = 0; i < 10; i++) {
      const file = formData.get(`locationImage_${i}`);
      if (file) locationImages.push(file);
    }
    if (locationImages.length === 0) {
      const single = formData.get("locationImage");
      if (single) locationImages.push(single);
    }

    const avatarImages = [];
    for (let i = 0; i < 10; i++) {
      const file = formData.get(`avatarImage_${i}`);
      if (file) avatarImages.push(file);
    }
    if (avatarImages.length === 0) {
      const single = formData.get("avatarImage");
      if (single) avatarImages.push(single);
    }

    const ai = new GoogleGenAI({ apiKey });

    async function uploadImageToGemini(file) {
      const buf = Buffer.from(await file.arrayBuffer());
      const mimeType = file.type || "image/jpeg";
      const blob = new Blob([buf], { type: mimeType });
      const uploaded = await ai.files.upload({
        file: blob,
        config: { mimeType, displayName: file.name || "image.jpg" },
      });
      return { uri: uploaded.uri, mimeType: uploaded.mimeType || mimeType };
    }

    const [locationDataArr, avatarDataArr] = await Promise.all([
      locationImages.length > 0
        ? Promise.all(locationImages.slice(0, 4).map(uploadImageToGemini))
        : Promise.resolve([]),
      avatarImages.length > 0
        ? Promise.all(avatarImages.slice(0, 2).map(uploadImageToGemini))
        : Promise.resolve([]),
    ]);

    const langMap = {
      english: "English", hindi: "Hindi", hinglish: "Hinglish", marathi: "Marathi",
      tamil: "Tamil", telugu: "Telugu", kannada: "Kannada", malayalam: "Malayalam",
      bengali: "Bengali", gujarati: "Gujarati", punjabi: "Punjabi", urdu: "Urdu", odia: "Odia",
    };
    const langName = langMap[language] || "English";

    const beatPlanPrompt = `You are a senior Indian real estate Instagram reel director.

Analyze this property script and design a HYBRID BEAT PLAN for a 55-65 second vertical Instagram Reel (~1 minute).

This reel uses TWO visual modes — both powered by Veo AI + Sarvam voice:
- Presenter beats (visual_type: "avatar") → Veo generates the presenter (person) walking and talking UGC creator style
- Property beats (visual_type: "property") → Veo generates room visuals with Sarvam TTS voiceover overlay

REQUIRED BEAT SEQUENCE (9-${MAX_BEATS} beats, 55-65 seconds total):
1. HOOK (visual_type: "avatar") — 5-6s — presenter steps out of car, door held open, walks toward camera and immediately starts talking about the property with energy — narration REQUIRED (10-18 words intro)
2. AVATAR_SEGMENT (visual_type: "avatar") — 5-7s — presenter walks toward property entrance, introduces key property highlights while walking
3. PROPERTY_VISUAL (visual_type: "property") — 4-6s — first key room (living room / main hall), voiceover with room size, layout, and standout feature
4. PROPERTY_VISUAL (visual_type: "property") — 4-6s — master bedroom with voiceover: size, wardrobe, balcony access
5. PROPERTY_VISUAL (visual_type: "property") — 4-6s — kitchen or dining area, voiceover with layout and finish quality
6. FEATURE_BURST (visual_type: "property") — 3-4s — price or key spec close-up shot, short punchy narration
7. PROPERTY_VISUAL (visual_type: "property") — 4-5s — outdoor space / amenity / view / another key room
8. AVATAR_SEGMENT (visual_type: "avatar") — 4-6s — presenter mid-reel: walks through a key area, highlights one emotional selling point (SKIP this beat if total would exceed 65 seconds)
9. CTA (visual_type: "avatar") — 5-6s — presenter stops walking, faces camera directly, delivers call-to-action

CONSTRAINTS:
- Total beats: 9-${MAX_BEATS}
- Total duration: 55-65 seconds
- Presenter beats (ALL avatar beats combined): maximum ${MAX_AVATAR_BEATS} total
- Property beats: minimum 4 property visuals — showcase DIFFERENT areas from the reference images
- Each property area appears ONCE — never repeat the same room
- Study the provided reference images to identify actual rooms and areas available

VEO PROMPT RULES for PRESENTER beats (visual_type: "avatar"):
- The presenter must be MOVING and WALKING throughout — UGC creator style, not standing still
- HOOK: presenter is ALREADY stepping out of the car, door is HELD OPEN — do NOT say "opens door"; say "door already open" or "stepping out of" to prevent Veo from animating a door-close
- AVATAR_SEGMENT: presenter walks through the property space, turns naturally to camera mid-step, speaks with genuine hand gestures
- CTA: presenter stops, turns directly to camera, warm smile, open-hand gesture
- Do NOT describe voice, audio, or speech — that is handled by Sarvam TTS separately
- Max 40 words per prompt
- HOOK example: "Presenter already stepping out of a white luxury SUV, car door held open, walks confidently toward camera with a natural warm smile. Smooth cinematic push-in. Golden hour. 9:16 vertical portrait."
- AVATAR_SEGMENT example: "Presenter walks through bright property interior, turns naturally to camera mid-step with genuine excitement and expressive hand gestures. Tracking medium close-up shot, luxury space moving behind. 9:16 vertical portrait."
- CTA example: "Presenter stops and turns directly to camera with warm authentic smile, extends one open hand toward viewer. Confident close-up, elegant property softly blurred behind. 9:16 vertical portrait."

VEO PROMPT RULES for PROPERTY beats (visual_type: "property"):
- Max 35 words
- Format: [specific area/room name]. [one camera movement]. [lighting/mood]. 9:16 portrait vertical. No people. No text overlays. No music.
- One room = one shot. Never mix two rooms in one prompt.
- Reference the actual rooms visible in the property images
- Good examples:
  "Rooftop infinity pool at sunset. Slow drone push-in toward city skyline. Warm golden light on water. 9:16 vertical. No people."
  "Grand marble entrance foyer with chandelier. Low-angle slow tracking left. Warm ambient glow. 9:16 vertical. No people."
  "Master bedroom with floor-to-ceiling windows. Slow dolly toward bed. Morning light streaming in. 9:16 vertical. No people."

NARRATION RULES (voiceover text that Sarvam TTS will speak over each beat):
- HOOK: 10-18 words in ${langName} — energetic opener as presenter exits the car and walks toward camera. Must feel like a UGC creator, not a commercial. Example: "Yaar, check out this incredible property — you won't believe what's inside!"
- AVATAR_SEGMENT: 20-30 words in ${langName}. Presenter speaks directly and conversationally while walking — highlight 2-3 key property features naturally
- PROPERTY_VISUAL: 18-28 words voiceover in ${langName} that DESCRIBES the room shown: mention the room type, approximate size if inferable from script, layout highlights (open plan? split level? connected to balcony?), and one distinctive finish or feature. Sound natural, not like a brochure. Example: "This living room is super spacious — easily seats twelve, has Italian marble floors and a double-height ceiling that just makes it feel incredible."
- FEATURE_BURST: 10-16 words in ${langName}, states the key price or spec out loud as a punchy fact
- CTA: 18-25 words in ${langName}, clear action instruction (call, book, visit, DM)
- No stage directions, no quotation marks — pure spoken words only

OVERLAY TEXT RULES:
- HOOK overlay: property name or tagline — 2-5 words, premium positioning
- FEATURE_BURST overlay: key stat (price, sqft, configuration) — max 5 words
- CTA overlay: action text — max 4 words (e.g., "Book Site Visit →")
- All other beats: overlay_text = null

OUTPUT: valid JSON only, no markdown fences, no extra text:
{
  "beats": [
    {
      "index": 0,
      "type": "HOOK",
      "duration_seconds": 4,
      "visual_type": "avatar",
      "veo_prompt": "Presenter already stepping out of a white luxury SUV, car door held open, walks confidently toward camera with natural warm smile, briefly glances up at building. Smooth cinematic push-in. Golden hour. 9:16 vertical portrait.",
      "overlay_text": "...",
      "narration": null,
      "lipsync_expression": "friendly"
    },
    {
      "index": 1,
      "type": "AVATAR_SEGMENT",
      "duration_seconds": 6,
      "visual_type": "avatar",
      "veo_prompt": "Presenter walks toward property entrance, turns naturally to camera mid-step, speaks with genuine enthusiasm and expressive hand gestures. Tracking medium close-up, grand property exterior moving behind. 9:16 vertical portrait.",
      "overlay_text": null,
      "narration": "...",
      "lipsync_expression": "friendly"
    },
    {
      "index": 2,
      "type": "PROPERTY_VISUAL",
      "duration_seconds": 5,
      "visual_type": "property",
      "veo_prompt": "...",
      "overlay_text": null,
      "narration": "...",
      "lipsync_expression": null
    },
    {
      "index": 3,
      "type": "PROPERTY_VISUAL",
      "duration_seconds": 5,
      "visual_type": "property",
      "veo_prompt": "...",
      "overlay_text": null,
      "narration": "...",
      "lipsync_expression": null
    },
    {
      "index": 4,
      "type": "PROPERTY_VISUAL",
      "duration_seconds": 5,
      "visual_type": "property",
      "veo_prompt": "...",
      "overlay_text": null,
      "narration": "...",
      "lipsync_expression": null
    },
    {
      "index": 5,
      "type": "FEATURE_BURST",
      "duration_seconds": 3,
      "visual_type": "property",
      "veo_prompt": "...",
      "overlay_text": "₹X Cr Onwards",
      "narration": "...",
      "lipsync_expression": null
    },
    {
      "index": 6,
      "type": "PROPERTY_VISUAL",
      "duration_seconds": 5,
      "visual_type": "property",
      "veo_prompt": "...",
      "overlay_text": null,
      "narration": "...",
      "lipsync_expression": null
    },
    {
      "index": 7,
      "type": "CTA",
      "duration_seconds": 6,
      "visual_type": "avatar",
      "veo_prompt": "Presenter stops walking and turns directly to camera with warm authentic smile, extends one open hand toward viewer. Confident close-up, elegant property softly blurred behind. 9:16 vertical portrait.",
      "overlay_text": "Book Site Visit →",
      "narration": "...",
      "lipsync_expression": "professional"
    }
  ],
  "voice_profile": "Brief description of presenter voice style for this reel",
  "full_narration": "Complete spoken text from all beats with narration combined, in order",
  "total_duration": 39
}

PROPERTY SCRIPT TO PLAN:
---
${script}
---`;

    const parts = [{ text: beatPlanPrompt }];
    locationDataArr.forEach((d) => parts.push({ fileData: { fileUri: d.uri, mimeType: d.mimeType } }));
    avatarDataArr.forEach((d) => parts.push({ fileData: { fileUri: d.uri, mimeType: d.mimeType } }));

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: [{ parts }],
    });

    const rawText = response.candidates?.[0]?.content?.parts?.[0]?.text?.trim();
    if (!rawText) {
      return NextResponse.json({ error: "Failed to generate beat plan" }, { status: 502 });
    }

    let beats = [];
    let voiceProfile = buildDefaultVoiceProfile(language);
    let fullNarration = script;

    const jsonMatch = rawText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try {
        const parsed = JSON.parse(jsonMatch[0]);
        if (Array.isArray(parsed.beats) && parsed.beats.length > 0) {
          beats = parsed.beats.slice(0, MAX_BEATS).map((b, i) => ({
            index: i,
            type: b.type || "PROPERTY_VISUAL",
            duration_seconds: clamp(b.duration_seconds || 4, 2, 8),
            visual_type: b.visual_type || "property",
            veo_prompt: b.veo_prompt || null,
            overlay_text: b.overlay_text || null,
            narration: b.narration || null,
            lipsync_expression: b.lipsync_expression || "friendly",
          }));
        }
        if (parsed.voice_profile) voiceProfile = parsed.voice_profile;
        if (parsed.full_narration) fullNarration = parsed.full_narration;
      } catch (_) {}
    }

    // Enforce max presenter beat limit — downgrade excess avatar beats to property
    let avatarCount = 0;
    beats = beats.map((b) => {
      if (b.visual_type === "avatar") {
        avatarCount++;
        if (avatarCount > MAX_AVATAR_BEATS) {
          return {
            ...b,
            visual_type: "property",
            type: "PROPERTY_VISUAL",
            veo_prompt: b.veo_prompt || "Luxury interior detail close-up. Slow push-in. Warm ambient light. 9:16 vertical. No people.",
            // Keep narration as voiceover for the downgraded property clip
          };
        }
      }
      return b;
    });

    // Ensure all beats have veo_prompt and narration — HOOK now talks while exiting car.
    beats = beats.map((b) => ({
      ...b,
      veo_prompt: b.visual_type === "property"
        ? (b.veo_prompt || buildFallbackVeoPrompt(b.type))
        : (b.veo_prompt || buildFallbackPresenterVeoPrompt(b.type)),
      narration: b.narration || buildFallbackNarration(b.type),
    }));

    if (beats.length === 0) {
      beats = buildFallbackBeats(script);
    }

    const totalDuration = beats.reduce((s, b) => s + (b.duration_seconds || 4), 0);

    // Synthesize full_narration from all avatar narrations if not provided
    if (!fullNarration || fullNarration === script) {
      const avatarLines = beats
        .filter((b) => b.visual_type === "avatar" && b.narration)
        .map((b) => b.narration);
      if (avatarLines.length > 0) fullNarration = avatarLines.join(" ");
    }

    // Legacy chunk format for backward-compat UI rendering
    const chunks = beats.map((b) => ({
      index: b.index,
      text: b.narration || b.overlay_text || `${b.type} — property visual`,
      estimatedSeconds: b.duration_seconds,
      veoPrompt: b.veo_prompt || "",
      cameraDirection: b.overlay_text || b.type,
      // Extended fields used by hybrid pipeline
      beatType: b.type,
      visualType: b.visual_type,
      overlayText: b.overlay_text,
      lipsyncExpression: b.lipsync_expression,
      narration: b.narration,
    }));

    return NextResponse.json({
      success: true,
      beats,
      voiceProfile,
      fullNarration,
      totalDuration,
      // Legacy compat
      chunks,
      masterVoicePrompt: voiceProfile,
      presenterDescription: "",
      totalChunks: beats.length,
      totalEstimatedDuration: totalDuration,
    });
  } catch (error) {
    console.error("[VeoLongAd] chunk-script error:", error);
    return NextResponse.json(
      { error: error.message || "Beat planning failed" },
      { status: 500 }
    );
  }
}

function clamp(val, min, max) {
  return Math.min(Math.max(val, min), max);
}

function buildDefaultVoiceProfile(language = "english") {
  return `Warm, confident Indian real estate creator speaking in ${language}. Direct to camera, authentic, conversational. Natural pauses, no performance voice.`;
}

function buildFallbackVeoPrompt(type) {
  const map = {
    PROPERTY_VISUAL: "Luxury living room interior, slow dolly push-in, warm ambient lighting. 9:16 vertical. No people.",
    FEATURE_BURST: "Premium property finishes close-up, shallow depth of field, elegant details. 9:16 vertical. No people.",
  };
  return map[type] || "Luxury property interior. Slow cinematic push-in. Warm light. 9:16 vertical. No people.";
}

function buildFallbackPresenterVeoPrompt(type) {
  const map = {
    HOOK: "Presenter already stepping out of a white luxury SUV, car door held open behind them, walks confidently toward camera with a natural warm smile, briefly glances up at the building. Smooth slow cinematic push-in. Golden hour warm light. 9:16 vertical portrait.",
    AVATAR_SEGMENT: "Presenter walks through the bright spacious property interior, turns naturally to camera mid-step, speaks directly with genuine enthusiasm and expressive hand gestures. Medium close-up tracking shot, luxury space visible behind. 9:16 vertical portrait.",
    CTA: "Presenter stops walking and turns directly to camera with a warm authentic smile, extends one open hand toward viewer in a welcoming gesture. Confident close-up, elegant property softly blurred behind. 9:16 vertical portrait.",
  };
  return map[type] || "Presenter walks through property, turns naturally to camera, speaks directly with energy. Medium close-up. 9:16 vertical portrait.";
}

function buildFallbackNarration(type) {
  const map = {
    HOOK: "Yaar, check out this incredible property — you are not going to believe what's inside!",
    AVATAR_SEGMENT: "I'm here at this stunning property and I have to say, this is one of the best I've seen in a long time.",
    CTA: "If you're serious about luxury living, contact us today to book your site visit. Don't miss this one.",
    PROPERTY_VISUAL: "Look at the incredible attention to detail in every corner of this space.",
    FEATURE_BURST: "Starting at just two crore — an unbelievable opportunity.",
  };
  return map[type] || "This property is absolutely stunning. You have to see it to believe it.";
}

function buildFallbackBeats(script) {
  const words = script.split(/\s+/).filter(Boolean);
  const third = Math.floor(words.length / 3);
  const introNarration = words.slice(0, Math.min(third, 28)).join(" ");
  const midNarration = words.slice(third, Math.min(third * 2, third + 28)).join(" ");
  const ctaNarration = words.slice(-22).join(" ");

  return [
    {
      index: 0,
      type: "HOOK",
      duration_seconds: 5,
      visual_type: "avatar",
      veo_prompt: buildFallbackPresenterVeoPrompt("HOOK"),
      overlay_text: "Premium Property",
      narration: buildFallbackNarration("HOOK"),
      lipsync_expression: "friendly",
    },
    {
      index: 1,
      type: "AVATAR_SEGMENT",
      duration_seconds: 6,
      visual_type: "avatar",
      veo_prompt: buildFallbackPresenterVeoPrompt("AVATAR_SEGMENT"),
      overlay_text: null,
      narration: introNarration,
      lipsync_expression: "friendly",
    },
    {
      index: 2,
      type: "PROPERTY_VISUAL",
      duration_seconds: 5,
      visual_type: "property",
      veo_prompt: "Grand living room with marble floors and double-height ceiling, slow left-to-right tracking shot, warm ambient lighting. 9:16 vertical. No people. No music.",
      overlay_text: null,
      narration: "This living room is absolutely massive — marble floors, double-height ceiling, and enough space to comfortably seat the whole family.",
      lipsync_expression: null,
    },
    {
      index: 3,
      type: "PROPERTY_VISUAL",
      duration_seconds: 5,
      visual_type: "property",
      veo_prompt: "Master bedroom with floor-to-ceiling windows and balcony access, slow dolly push-in toward window. Soft morning light. 9:16 vertical. No people. No music.",
      overlay_text: null,
      narration: "The master bedroom is huge — easily fits a king bed, has a walk-in wardrobe and glass doors that open directly onto the private balcony.",
      lipsync_expression: null,
    },
    {
      index: 4,
      type: "PROPERTY_VISUAL",
      duration_seconds: 5,
      visual_type: "property",
      veo_prompt: "Modern modular kitchen with island counter and premium appliances, slow right-to-left tracking shot. Warm under-cabinet lighting. 9:16 vertical. No people. No music.",
      overlay_text: null,
      narration: "Look at this kitchen — fully modular with an island counter, imported fittings, and enough storage to make any home chef fall in love.",
      lipsync_expression: null,
    },
    {
      index: 5,
      type: "FEATURE_BURST",
      duration_seconds: 3,
      visual_type: "property",
      veo_prompt: "Premium property finishes close-up — marble countertop, brass hardware, wide-plank flooring. Shallow depth of field. 9:16 vertical. No people. No music.",
      overlay_text: "Starting ₹X Cr",
      narration: "And all of this starts at just two crore. Seriously unbeatable value.",
      lipsync_expression: null,
    },
    {
      index: 6,
      type: "PROPERTY_VISUAL",
      duration_seconds: 5,
      visual_type: "property",
      veo_prompt: "Building rooftop amenity area or landscaped outdoor space with city view, slow aerial push-out. Golden hour light. 9:16 vertical. No people. No music.",
      overlay_text: null,
      narration: midNarration || "And then there's this — the rooftop amenity deck with panoramic city views. Perfect for evening unwinding.",
      lipsync_expression: null,
    },
    {
      index: 7,
      type: "CTA",
      duration_seconds: 6,
      visual_type: "avatar",
      veo_prompt: buildFallbackPresenterVeoPrompt("CTA"),
      overlay_text: "Book Site Visit →",
      narration: ctaNarration,
      lipsync_expression: "professional",
    },
  ];
}
